import { app, BrowserWindow, ipcMain, dialog } from 'electron';
import path from 'path';
import { spawn, ChildProcess } from 'child_process';
import axios from 'axios';
import { setupIpcHandlers } from './ipc/handlers';
import { autoUpdater } from 'electron-updater';

let mainWindow: BrowserWindow | null = null;
let serverProcess: ChildProcess | null = null;
const SERVER_PORT = process.env.PORT || 3000;
const SERVER_URL = `http://localhost:${SERVER_PORT}`;

// ─── Auto Updater ─────────────────────────────────────────────────────────────
autoUpdater.autoDownload = false;
autoUpdater.on('update-available', () => {
  mainWindow?.webContents.send('update-available');
});
autoUpdater.on('update-downloaded', () => {
  autoUpdater.quitAndInstall();
});
ipcMain.on('check-for-updates', () => { autoUpdater.checkForUpdates(); });
ipcMain.on('download-update', () => { autoUpdater.downloadUpdate(); });

// ─── Start Express Backend ─────────────────────────────────────────────────────
async function startServer(): Promise<void> {
  const serverPath = path.join(__dirname, '../dist/server.cjs');

  serverProcess = spawn(process.execPath, [serverPath], {
    env: { ...process.env, NODE_ENV: 'production', PORT: String(SERVER_PORT) },
    stdio: ['ignore', 'pipe', 'pipe'],
  });

  serverProcess.stdout?.on('data', (data) => console.log('[server]', data.toString()));
  serverProcess.stderr?.on('data', (data) => console.error('[server err]', data.toString()));

  serverProcess.on('exit', (code) => {
    if (code !== 0 && mainWindow) {
      dialog.showErrorBox('Server Error', `Backend exited with code ${code}.`);
    }
  });

  // Wait for health check (up to 20 seconds)
  for (let i = 0; i < 20; i++) {
    try {
      await axios.get(`${SERVER_URL}/api/health`);
      console.log('[electron] Backend server is up ✅');
      return;
    } catch {
      console.log(`[electron] Waiting for server... attempt ${i + 1}/20`);
      await new Promise<void>((resolve) => setTimeout(resolve, 1000));
    }
  }
  throw new Error('Backend server failed to start after 20 seconds.');
}

// ─── Create Main Window ────────────────────────────────────────────────────────
function createWindow(): void {
  const iconPath = path.join(__dirname, '../assets/icon.png');

  mainWindow = new BrowserWindow({
    width: 1280,
    height: 800,
    minWidth: 900,
    minHeight: 600,
    show: false,               // show only after ready-to-show
    icon: iconPath,
    title: 'LMS Platform — Building Makers',
    webPreferences: {
      preload: path.join(__dirname, 'preload.cjs'),
      contextIsolation: true,
      nodeIntegration: false,
      webSecurity: true,
    },
  });

  mainWindow.loadURL(SERVER_URL);

  // Show window only when fully loaded (prevents white flash)
  mainWindow.once('ready-to-show', () => {
    mainWindow?.show();
    mainWindow?.focus();
  });

  // Handle external links in system browser
  mainWindow.webContents.setWindowOpenHandler(({ url }) => {
    if (url.startsWith('http://localhost')) return { action: 'allow' };
    require('electron').shell.openExternal(url);
    return { action: 'deny' };
  });

  mainWindow.on('closed', () => { mainWindow = null; });
}

// ─── App Lifecycle ─────────────────────────────────────────────────────────────
app.on('ready', async () => {
  try {
    await startServer();
    createWindow();
    setupIpcHandlers();
  } catch (err: any) {
    dialog.showErrorBox('Startup Error', err.message || 'Unknown error');
    app.quit();
  }
});

app.on('window-all-closed', () => {
  if (serverProcess) {
    serverProcess.kill('SIGTERM');
    serverProcess = null;
  }
  if (process.platform !== 'darwin') app.quit();
});

app.on('activate', () => {
  if (mainWindow === null) createWindow();
});
